#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <stdbool.h>

/* ============================================================================
 * PHYSICAL DESIGN OF IoT - Microcontroller Sensor Interface
 * Demonstrates: Sensors, Microcontroller (MCU), Communication Module
 * Target: Arduino/ESP32 class MCU
 * ============================================================================ */

// ============================================================================
// CONSTANTS AND CONFIGURATION
// ============================================================================
#define MAX_SENSORS 8
#define ADC_RESOLUTION 1024  // 10-bit ADC
#define VREF 3.3              // Reference voltage in volts
#define TEMP_THRESHOLD 30     // Temperature threshold in Celsius

// Communication module types (Physical Design: Communication Modules)
typedef enum {
    COMM_BLE,      // Bluetooth Low Energy
    COMM_WIFI,     // Wi-Fi
    COMM_ZIGBEE,   // Zigbee
    COMM_LORA      // LoRaWAN
} CommModuleType;

// ============================================================================
// SENSOR STRUCTURES (Physical Design: Sensors)
// ============================================================================
typedef struct {
    uint8_t pin;           // GPIO pin number
    char name[32];         // Sensor name
    float (*read_func)(uint8_t); // Function pointer to read sensor
} Sensor;

typedef struct {
    uint8_t sensor_id;
    char type[16];         // "temperature", "humidity", etc.
    float value;
    char unit[8];
    bool alert_triggered;
} SensorReading;

// ============================================================================
// SENSOR READING FUNCTIONS (Simulated hardware access)
// ============================================================================

/* Simulate reading ADC value from a hardware sensor */
uint16_t read_adc(uint8_t pin) {
    // In real hardware, this would read from ADC register
    // Simulating: return random ADC value
    return (uint16_t)(rand() % ADC_RESOLUTION);
}

/* Convert ADC value to temperature (thermistor calculation) 
 * Physical Design: Temperature Sensor (thermistor) */
float read_temperature(uint8_t pin) {
    uint16_t adc_value = read_adc(pin);

    // Simplified NTC thermistor calculation
    float voltage = (adc_value * VREF) / ADC_RESOLUTION;
    float resistance = 10000.0 / ((VREF / voltage) - 1.0);

    // Steinhart-Hart equation approximation (simplified)
    float temp = 1.0 / (0.003354 + 0.000256 * log(resistance/10000.0));

    return temp - 273.15;  // Convert Kelvin to Celsius
}

/* Read humidity sensor (DHT11/DHT22 style) */
float read_humidity(uint8_t pin) {
    uint16_t adc_value = read_adc(pin);

    // Simulate humidity calculation from ADC
    float humidity = (adc_value * 100.0) / ADC_RESOLUTION;

    return humidity;
}

/* Read light sensor (LDR/photodiode) */
float read_light(uint8_t pin) {
    uint16_t adc_value = read_adc(pin);

    // Convert to lux (simplified)
    float voltage = (adc_value * VREF) / ADC_RESOLUTION;
    float lux = (voltage / 10.0) * 1000.0;

    return lux;
}

// ============================================================================
// ACTUATOR CONTROL (Physical Design: Actuators)
// ============================================================================

/* Control an LED actuator */
void control_led(uint8_t pin, bool state) {
    printf("[Actuator] LED on pin %d: %s\n", pin, state ? "ON" : "OFF");
    // In real hardware: digitalWrite(pin, state ? HIGH : LOW);
}

/* Control a relay (for high-power devices) */
void control_relay(uint8_t pin, bool state) {
    printf("[Actuator] Relay on pin %d: %s\n", pin, state ? "CLOSED" : "OPEN");
    // In real hardware: digitalWrite(pin, state ? HIGH : LOW);
}

// ============================================================================
// COMMUNICATION MODULE (Physical Design: Communication Modules)
// ============================================================================

typedef struct {
    CommModuleType type;
    bool connected;
    char endpoint[64];
} CommModule;

/* Initialize communication module */
bool comm_init(CommModule *mod, CommModuleType type, char *endpoint) {
    mod->type = type;
    mod->connected = false;
    strncpy(mod->endpoint, endpoint, 63);

    const char *type_str[] = {"BLE", "Wi-Fi", "Zigbee", "LoRaWAN"};
    printf("[Communication] Initializing %s module...\n", type_str[type]);

    // Simulate connection establishment
    mod->connected = true;
    printf("[Communication] Connected to %s\n", endpoint);

    return true;
}

/* Transmit data to cloud/server */
bool comm_transmit(CommModule *mod, SensorReading *readings, uint8_t count) {
    if (!mod->connected) {
        printf("[Communication] Error: Not connected!\n");
        return false;
    }

    printf("[Communication] Sending %d readings to %s:\n", count, mod->endpoint);

    for (uint8_t i = 0; i < count; i++) {
        printf("  - %s: %.2f %s %s\n", 
               readings[i].type, 
               readings[i].value, 
               readings[i].unit,
               readings[i].alert_triggered ? "[ALERT]" : "");
    }

    return true;
}

// ============================================================================
// POWER MANAGEMENT (Physical Design: Power Management)
// ============================================================================

/* Enter low power sleep mode */
void enter_low_power_mode(uint16_t duration_ms) {
    printf("[Power] Entering sleep mode for %d ms...\n", duration_ms);
    // In real hardware: ESP.deepSleep() or similar
    printf("[Power] Waking up - reduced power consumption achieved\n");
}

/* Get battery level (simulated) */
uint8_t get_battery_level(void) {
    // In real hardware: read from ADC connected to battery
    return 85;  // 85% battery
}

// ============================================================================
// MAIN IoT DEVICE PROGRAM
// ============================================================================

int main(void) {
    printf("========================================\n");
    printf(" IoT Device - Physical Design Demo\n");
    printf("========================================\n\n");

    // Initialize sensors (Physical Design: Sensors)
    Sensor sensors[MAX_SENSORS];
    uint8_t sensor_count = 0;

    // Add temperature sensor
    sensors[sensor_count].pin = 34;
    strcpy(sensors[sensor_count].name, "TempSensor");
    sensors[sensor_count].read_func = read_temperature;
    sensor_count++;

    // Add humidity sensor
    sensors[sensor_count].pin = 35;
    strcpy(sensors[sensor_count].name, "HumiditySensor");
    sensors[sensor_count].read_func = read_humidity;
    sensor_count++;

    // Add light sensor
    sensors[sensor_count].pin = 36;
    strcpy(sensors[sensor_count].name, "LightSensor");
    sensors[sensor_count].read_func = read_light;
    sensor_count++;

    printf("[System] Initialized %d sensors\n\n", sensor_count);

    // Initialize communication module (Physical Design: Communication)
    CommModule comm_module;
    comm_init(&comm_module, COMM_WIFI, "https://api.iot-cloud.example.com/data");

    // Main loop
    printf("\n--- Starting Main Loop ---\n");

    for (int cycle = 0; cycle < 3; cycle++) {
        printf("\n=== Cycle %d ===\n", cycle + 1);

        SensorReading readings[MAX_SENSORS];

        // Step 1: Read all sensors
        printf("[1] Reading sensors...\n");
        for (uint8_t i = 0; i < sensor_count; i++) {
            readings[i].sensor_id = i;
            readings[i].value = sensors[i].read_func(sensors[i].pin);
            readings[i].alert_triggered = false;

            // Set sensor type and unit based on index
            if (i == 0) {
                strcpy(readings[i].type, "temperature");
                strcpy(readings[i].unit, "°C");

                // Check threshold (Physical Design: Decision making)
                if (readings[i].value > TEMP_THRESHOLD) {
                    readings[i].alert_triggered = true;
                    printf("  [ALERT] High temperature detected!\n");
                    control_led(2, true);  // Turn on warning LED
                }
            } else if (i == 1) {
                strcpy(readings[i].type, "humidity");
                strcpy(readings[i].unit, "%");
            } else {
                strcpy(readings[i].type, "light");
                strcpy(readings[i].unit, "lux");
            }

            printf("  %s: %.2f %s\n", readings[i].type, readings[i].value, readings[i].unit);
        }

        // Step 2: Transmit data (Physical Design: Communication Module)
        printf("\n[2] Transmitting data...\n");
        comm_transmit(&comm_module, readings, sensor_count);

        // Step 3: Power management
        printf("\n[3] Battery level: %d%%\n", get_battery_level());
        enter_low_power_mode(5000);  // Sleep for 5 seconds
    }

    printf("\n--- Device Stopped ---\n");

    return 0;
}

import java.util.*;
import java.util.concurrent.*;

/**
 * PHYSICAL DESIGN OF IoT - Gateway Application
 * Demonstrates: Gateway devices, data aggregation, protocol translation
 * Target: Raspberry Pi, Industrial Gateway
 */

// ============================================================================
// DATA MODELS
// ============================================================================

class SensorData {
    private final String deviceId;
    private final String sensorType;
    private final double value;
    private final String unit;
    private final long timestamp;

    public SensorData(String deviceId, String sensorType, double value, String unit) {
        this.deviceId = deviceId;
        this.sensorType = sensorType;
        this.value = value;
        this.unit = unit;
        this.timestamp = System.currentTimeMillis();
    }

    // Getters
    public String getDeviceId() { return deviceId; }
    public String getSensorType() { return sensorType; }
    public double getValue() { return value; }
    public String getUnit() { return unit; }
    public long getTimestamp() { return timestamp; }

    @Override
    public String toString() {
        return String.format("[%s] %s: %.2f %s", deviceId, sensorType, value, unit);
    }
}

// Communication protocol types (Physical Design: Communication Modules)
enum Protocol {
    MQTT,    // Lightweight messaging for IoT
    HTTP,    // REST API
    COAP,    // Constrained Application Protocol
    WEBSOCKET
}

// Device category (Physical Design: IoT Device Categories)
enum DeviceCategory {
    CONSTRAINED,    // Limited resources (RFID, simple sensors)
    INTERMEDIATE,   // Moderate resources (smart home devices)
    GATEWAY         // High resources (Raspberry Pi, industrial gateways)
}

// ============================================================================
// IoT NODE (Represents constrained/intermediate device)
// ============================================================================

class IoTNode {
    private final String nodeId;
    private final DeviceCategory category;
    private final Set<String> supportedSensors;
    private Protocol communicationProtocol;
    private boolean isActive;

    public IoTNode(String nodeId, DeviceCategory category) {
        this.nodeId = nodeId;
        this.category = category;
        this.supportedSensors = new HashSet<>();
        this.isActive = false;

        // Set default protocol based on device category
        this.communicationProtocol = (category == DeviceCategory.CONSTRAINED) 
            ? Protocol.COAP : Protocol.MQTT;
    }

    public void addSensor(String sensorType) {
        supportedSensors.add(sensorType);
    }

    public void setProtocol(Protocol protocol) {
        this.communicationProtocol = protocol;
    }

    public void activate() { this.isActive = true; }
    public void deactivate() { this.isActive = false; }

    // Simulate receiving data from this node
    public List<SensorData> readSensorData() {
        List<SensorData> dataList = new ArrayList<>();
        Random rand = new Random();

        for (String sensor : supportedSensors) {
            double value = 0;
            String unit = "";

            switch (sensor.toLowerCase()) {
                case "temperature":
                    value = 15 + rand.nextDouble() * 20;  // 15-35°C
                    unit = "°C";
                    break;
                case "humidity":
                    value = 30 + rand.nextDouble() * 60;  // 30-90%
                    unit = "%";
                    break;
                case "pressure":
                    value = 990 + rand.nextDouble() * 30;  // 990-1020 hPa
                    unit = "hPa";
                    break;
                case "light":
                    value = rand.nextDouble() * 1000;  // 0-1000 lux
                    unit = "lux";
                    break;
            }

            dataList.add(new SensorData(nodeId, sensor, value, unit));
        }

        return dataList;
    }

    // Getters
    public String getNodeId() { return nodeId; }
    public DeviceCategory getCategory() { return category; }
    public Protocol getProtocol() { return communicationProtocol; }
    public boolean isActive() { return isActive; }
    public Set<String> getSupportedSensors() { return supportedSensors; }
}

// ============================================================================
// IoT GATEWAY (Physical Design: Gateway Devices)
// ============================================================================

class IoTGateway {
    private final String gatewayId;
    private final Map<String, IoTNode> connectedNodes;
    private final BlockingQueue<SensorData> dataQueue;
    private final ExecutorService executor;
    private boolean running;

    public IoTGateway(String gatewayId) {
        this.gatewayId = gatewayId;
        this.connectedNodes = new ConcurrentHashMap<>();
        this.dataQueue = new LinkedBlockingQueue<>(1000);
        this.executor = Executors.newFixedThreadPool(4);
        this.running = false;
    }

    /**
     * Register a new IoT node to this gateway
     * Physical Design: Connecting constrained devices to gateway
     */
    public void registerNode(IoTNode node) {
        connectedNodes.put(node.getNodeId(), node);
        System.out.println("[Gateway] Registered node: " + node.getNodeId() + 
                          " (Category: " + node.getCategory() + ")");
    }

    /**
     * Start collecting data from all registered nodes
     */
    public void startDataCollection() {
        running = true;

        // Submit data collection tasks
        for (IoTNode node : connectedNodes.values()) {
            if (node.isActive()) {
                executor.submit(() -> collectFromNode(node));
            }
        }

        // Submit data processing task
        executor.submit(this::processDataQueue);

        System.out.println("[Gateway] Data collection started");
    }

    /**
     * Collect data from a specific node
     */
    private void collectFromNode(IoTNode node) {
        while (running) {
            try {
                List<SensorData> readings = node.readSensorData();
                for (SensorData data : readings) {
                    dataQueue.offer(data);
                }
                System.out.println("[Gateway] Collected " + readings.size() + 
                                  " readings from " + node.getNodeId());

                Thread.sleep(5000);  // Collection interval
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            }
        }
    }

    /**
     * Process collected data (filter, aggregate, forward)
     */
    private void processDataQueue() {
        while (running) {
            try {
                SensorData data = dataQueue.poll(1, TimeUnit.SECONDS);
                if (data != null) {
                    processAndForward(data);
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            }
        }
    }

    /**
     * Process sensor data and forward to cloud
     * Physical Design: Protocol translation and data aggregation
     */
    private void processAndForward(SensorData data) {
        // Example: Check for alerts
        if (data.getSensorType().equals("temperature") && data.getValue() > 30) {
            System.out.println("[Gateway] ALERT: High temperature from " + 
                              data.getDeviceId() + ": " + data.getValue() + "°C");
        }

        // Forward to cloud (simulated)
        forwardToCloud(data);
    }

    /**
     * Forward data to cloud using appropriate protocol
     */
    private void forwardToCloud(SensorData data) {
        // In real implementation, this would use MQTT/HTTP client
        System.out.println("[Gateway] → Cloud: " + data);
    }

    public void stop() {
        running = false;
        executor.shutdown();
        try {
            executor.awaitTermination(5, TimeUnit.SECONDS);
        } catch (InterruptedException e) {
            e.printStackTrace();
        }
        System.out.println("[Gateway] Stopped");
    }
}

// ============================================================================
// MAIN PROGRAM
// ============================================================================

public class IoTGatewayDemo {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("===========================================");
        System.out.println(" IoT Gateway - Physical Design Demo");
        System.out.println("===========================================\n");

        // Create gateway (Physical Design: Gateway device like Raspberry Pi)
        IoTGateway gateway = new IoTGateway("GATEWAY-001");

        // Create and configure IoT nodes

        // Node 1: Constrained device (Physical Design: Constrained Devices)
        IoTNode node1 = new IoTNode("SENSOR-001", DeviceCategory.CONSTRAINED);
        node1.addSensor("temperature");
        node1.addSensor("humidity");
        node1.setProtocol(Protocol.COAP);
        node1.activate();

        // Node 2: Intermediate device
        IoTNode node2 = new IoTNode("SENSOR-002", DeviceCategory.INTERMEDIATE);
        node2.addSensor("temperature");
        node2.addSensor("humidity");
        node2.addSensor("pressure");
        node2.addSensor("light");
        node2.setProtocol(Protocol.MQTT);
        node2.activate();

        // Node 3: Another constrained device
        IoTNode node3 = new IoTNode("SENSOR-003", DeviceCategory.CONSTRAINED);
        node3.addSensor("temperature");
        node3.setProtocol(Protocol.COAP);
        node3.activate();

        // Register nodes with gateway
        System.out.println("--- Registering IoT Nodes ---\n");
        gateway.registerNode(node1);
        gateway.registerNode(node2);
        gateway.registerNode(node3);

        // Start gateway
        System.out.println("\n--- Starting Gateway ---\n");
        gateway.startDataCollection();

        // Let it run for a while
        Thread.sleep(15000);

        // Stop gateway
        gateway.stop();

        System.out.println("\n--- Demo Complete ---");
    }
}
